import{_ as i,o as l,c as t,ag as a}from"./chunks/framework.lDGEKPiH.js";const m=JSON.parse('{"title":"标准库 (Standard Library)","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/stdlib.md","filePath":"zh/guide/stdlib.md"}'),o={name:"zh/guide/stdlib.md"};function d(c,e,s,r,n,u){return l(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="标准库-standard-library" tabindex="-1">标准库 (Standard Library) <a class="header-anchor" href="#标准库-standard-library" aria-label="Permalink to &quot;标准库 (Standard Library)&quot;">​</a></h1><p>Relon 旨在成为配置领域的确定性超集。因此，它的标准库故意移除了所有不确定的副产品特性（例如网络请求、文件 I/O、当前时间等）。标准库的所有函数在给定相同的输入时，始终会产生完全一致的数据输出。</p><h2 id="数据断言-is" tabindex="-1">数据断言 (is) <a class="header-anchor" href="#数据断言-is" aria-label="Permalink to &quot;数据断言 (is)&quot;">​</a></h2><p><code>std/is</code> 命名空间提供了一系列纯函数，用于判定数据的运行时类型：</p><ul><li><code>is.null(value)</code></li><li><code>is.bool(value)</code></li><li><code>is.int(value)</code></li><li><code>is.float(value)</code></li><li><code>is.number(value)</code>: 匹配 Int 和 Float。</li><li><code>is.string(value)</code></li><li><code>is.list(value)</code></li><li><code>is.dict(value)</code></li><li><code>is.empty(value)</code>: 判断字符串、列表或字典是否为空。</li></ul><h2 id="契约守卫装饰器-ensure" tabindex="-1">契约守卫装饰器 (ensure) <a class="header-anchor" href="#契约守卫装饰器-ensure" aria-label="Permalink to &quot;契约守卫装饰器 (ensure)&quot;">​</a></h2><p><code>std/ensure</code> 下包含了一系列强大的校验拦截器，通常与 <code>@</code> 装饰器搭配在 Schema 中使用。如果断言失败，整个配置构建将会崩溃，从而在早期暴露问题：</p><ul><li><code>@ensure.required_fields([&quot;host&quot;, &quot;port&quot;])</code>: 确保当前字典包含指定的键。</li><li><code>@ensure.at_least(1024, &quot;msg?&quot;)</code>: 确保数字大于或等于特定值。</li><li><code>@ensure.requires(&quot;tls&quot;, &quot;cert&quot;, &quot;msg?&quot;)</code>: 如果当前字典有 <code>tls</code> 字段，则必须同时有 <code>cert</code> 字段。</li><li><code>@ensure.fields_equal(&quot;password&quot;, &quot;confirm&quot;)</code>: 确保两个字段的值严格相等。</li></ul><h2 id="字典操作-dict" tabindex="-1">字典操作 (dict) <a class="header-anchor" href="#字典操作-dict" aria-label="Permalink to &quot;字典操作 (dict)&quot;">​</a></h2><ul><li><code>dict.merge(base, patch)</code>: 类似于使用 <code>+</code> 算子，执行深度合并。</li><li><code>dict.keys(dict)</code>: 返回字典包含的所有键列表（由于是 <code>BTreeMap</code> 驱动，输出通常是有序的）。</li><li><code>dict.values(dict)</code>: 提取字典的所有值。</li><li><code>dict.has_key(dict, key)</code>: 判断键是否存在。</li></ul><h2 id="列表与字符串-list-string" tabindex="-1">列表与字符串 (list &amp; string) <a class="header-anchor" href="#列表与字符串-list-string" aria-label="Permalink to &quot;列表与字符串 (list &amp; string)&quot;">​</a></h2><h3 id="列表操作-list" tabindex="-1">列表操作 (list) <a class="header-anchor" href="#列表操作-list" aria-label="Permalink to &quot;列表操作 (list)&quot;">​</a></h3><ul><li><code>list.len(list)</code>: 数组长度。</li><li><code>list.first(list)</code>: 获取首个元素。</li><li><code>list.contains(list, item)</code>: 是否包含指定元素。</li><li><code>list.compact(list)</code>: 返回一个新数组，其中去除了所有的 <code>null</code> 元素。</li></ul><h3 id="字符串操作-string" tabindex="-1">字符串操作 (string) <a class="header-anchor" href="#字符串操作-string" aria-label="Permalink to &quot;字符串操作 (string)&quot;">​</a></h3><ul><li><code>string.len(str)</code>: 字符串长度。</li><li><code>string.split(str, separator)</code>: 切割字符串为列表。</li><li><code>string.join(list, separator)</code>: 把列表拼接为字符串。</li><li><code>string.replace(str, old, new)</code>: 替换子串。</li><li><code>string.upper(str)</code> / <code>string.lower(str)</code>: 大小写转换。</li><li><code>string.contains(str, substr)</code>: 是否包含片段。</li></ul><h2 id="数学操作-math" tabindex="-1">数学操作 (math) <a class="header-anchor" href="#数学操作-math" aria-label="Permalink to &quot;数学操作 (math)&quot;">​</a></h2><ul><li><code>math.abs(val)</code>: 绝对值。</li><li><code>math.min(a, b)</code> / <code>math.max(a, b)</code>: 最大最小值。</li><li><code>math.clamp(val, min_val, max_val)</code>: 将数字限制在指定范围内。</li></ul><p>通过组合这套小巧而紧凑的库，你能够在不借助外部脚本的情况下，利用纯 Relon 代码完成极其复杂的格式化、校验以及组件聚合工作。</p>',18)])])}const q=i(o,[["render",d]]);export{m as __pageData,q as default};
